    23→/**
    24→ * Extension supporting the Symfony Validator component in forms.
    25→ *
    26→ * @author Bernhard Schussek <bschussek@gmail.com>
    27→ */
    28→class ValidatorExtension extends AbstractExtension
    29→{
    30→    private ValidatorInterface $validator;
    31→    private ?FormRendererInterface $formRenderer;
    32→    private ?TranslatorInterface $translator;
    33→    private bool $legacyErrorMessages;
    34→
    35→    public function __construct(ValidatorInterface $validator, bool $legacyErrorMessages = true, ?FormRendererInterface $formRenderer = null, ?TranslatorInterface $translator = null)
    36→    {
    37→        $this->legacyErrorMessages = $legacyErrorMessages;
    38→
    39→        /** @var ClassMetadata $metadata */
    40→        $metadata = $validator->getMetadataFor(\Symfony\Component\Form\Form::class);
    41→
    42→        // Register the form constraints in the validator programmatically.
    43→        // This functionality is required when using the Form component without
    44→        // the DIC, where the XML file is loaded automatically. Thus the following
    45→        // code must be kept synchronized with validation.xml
    46→
    47→        $metadata->addConstraint(new Form());
    48→        $metadata->addConstraint(new Traverse(false));
    49→
    50→        $this->validator = $validator;
    51→        $this->formRenderer = $formRenderer;
    52→        $this->translator = $translator;
    53→    }
    54→
    55→    public function loadTypeGuesser(): ?FormTypeGuesserInterface
    56→    {
    57→        return new ValidatorTypeGuesser($this->validator);
    58→    }
    59→
    60→    protected function loadTypeExtensions(): array
    61→    {
    62→        return [
    63→            new Type\FormTypeValidatorExtension($this->validator, $this->legacyErrorMessages, $this->formRenderer, $this->translator),
    64→            new Type\RepeatedTypeValidatorExtension(),
    65→            new Type\SubmitTypeValidatorExtension(),
    66→        ];
    67→    }
    68→}
